var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nSN No. RS187L0005-11: <color=#ffd34c>【기록-005】 검토 회의</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>     \\nSN No. RS187L0005-11：<color=#ffd34c>【記録-005】 検討会議</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nSN No. RS187L0005-11: <color=#ffd34c>【Record-005】 Review Conference</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nSN No. RS187L0005-11: <color=#ffd34c>【記錄-005】 討論會議</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_QM","text":{"KOREA":"적합인자 확보 계획은 어떻게 되어가고 있죠?","JPN":"適合因子の確保計画は？","ENG":"How goes the plans for acquiring adequate factor?","TWN":"適性因子的確保計畫怎麼樣了？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"FINLY_NPC_NULL_NULL","text":{"KOREA":"네, 순조롭게 진행되고 있습니다.","JPN":"順調に進んでいます。","ENG":"Yes, it's going smoothly.","TWN":"是，進行得很順利。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FINLY_NPC_NULL_NULL","text":{"KOREA":"이번엔 마침 용병으로 활동중인 표본들과 연락이 닿아서, 보수를 미끼로 불러들인 상황입니다.","JPN":"今回は傭兵として活動してるターゲットとの連絡がついたので、報酬をエサに呼び寄せました。","ENG":"I was able to get in contact with mercenary specimens, so I lured them in with high pay.","TWN":"這次正好聯絡到了身為現役傭兵的活動中標本，並以報酬作為誘餌。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FINLY_NPC_NULL_NULL","text":{"KOREA":"카운터 하나와 용병 넷을 오늘 지정 섹터로 소집할 예정이고,","JPN":"カウンター1名と傭兵4名を、本日指定セクターへ招集することになっており、","ENG":"A Counter, along with four mercenaries will gather at the designated sector today.","TWN":"今天預計召集一名制裁者和四名傭兵到指定區域。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FINLY_NPC_NULL_NULL","text":{"KOREA":"협력할 여지가 생기지 않도록 카운터는 일정에 시간차를 둬서 따로 포획하려 합니다.","JPN":"協力する余地が生じないよう、カウンターは一定の時間をおいて、個別で確保する予定です。","ENG":"And in order to prevent their coordination, I'm going to capture the Counter after a delay.","TWN":"為了防止他們有合作的可能，制裁者會隔一段時間差再派過去，然後分別進行捕獲。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FINLY_NPC_NULL_NULL","text":{"KOREA":"표면상으론 정찰임무인줄 알고 있을 테니 의심은 전혀 하지 못할 겁니다.","JPN":"表向きには偵察任務ということになっているので、怪しまれる心配はありません。","ENG":"They will have no clue, since on the surface, it's just a scouting mission.","TWN":"表面上，他們會以為這只是個偵察任務，完全不會起疑。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_QM","text":{"KOREA":"훌륭하군요.","JPN":"素晴らしいですね。","ENG":"Excellent.","TWN":"真是不錯的計畫呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_QM","text":{"KOREA":"안전한 생포를 위해 리플레이서 부대를 보내겠습니다. 그럼 계속 수고해주세요.","JPN":"安全に捕らえるために、リプレイサー部隊を手配します。では、引き続き頑張ってください。","ENG":"I will send out a squad of Replacers to safely capture them. Please continue to keep up the work.","TWN":"為了能安全地捕獲他們，我們會派克隆部隊過去。那麼之後就辛苦你了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FINLY_NPC_NULL_NULL","text":{"KOREA":"......감사합니다. 최선을 다하겠습니다.","JPN":"……ありがとうございます。最善を尽くします。","ENG":"Thank you. I will do my best.","TWN":"……非常感謝，我會全力以赴的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"에디 피셔는...... 놈들의 함정에 걸려든 거였군.","JPN":"エディー・フィシャーは……やつらの罠にかかったんだな。","ENG":"Eddie Fisher was... lured into their trap.","TWN":"艾迪·費舍爾……中了他們的陷阱了啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"최근 도시외곽에서 자주 일어나던 실종사건의 희생자들 중 한 명인 것 같네요.","JPN":"最近郊外で頻繁に起きていた、行方不明事件の犠牲者だと思われます。","ENG":"He must be one of the victims in the recent disappearances that have been occurring out of town.","TWN":"在最近郊外經常發生的失蹤事件中，他也變成了一名犧牲者呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"아마 실험체로 쓰여졌거나...... 현장에서 사망했다고 봐야 할 것 같습니다.","JPN":"たぶん実験体として使われたか……現場で死亡したとみるしかないでしょう。","ENG":"He was probably used as an experiment subject... or killed at the site already.","TWN":"我們只能看作他被當成了實驗體……或是在現場死亡了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"안타까운 일이야.","JPN":"残念だな。","ENG":"How unfortunate.","TWN":"真是遺憾。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"우리가 한 발 늦은 것 같아서 더더욱 그런 느낌이 드는군.","JPN":"一足遅かったというのが、なおいっそう残念だ。","ENG":"It feels worse since things could have been different if we didn't postpone.","TWN":"因為我們晚了一步，所以就更有這種感覺了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"비록 저희와 관계된 일은 아니지만......","JPN":"直接関連があるわけではありませんが……","ENG":"Although this case has nothing to do with us...","TWN":"儘管這件事和我們沒有關係……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"저희 인사계획을 망가트린 놈들에게 한 방 먹여준다고 뭐라고 할 사람들도 없겠죠.","JPN":"人事計画を台無しにしたやつらを痛い目に遭わせても、文句は言われないはずです。","ENG":"Nobody would shame us for taking a shot at the ones who ruined our recruitment plan.","TWN":"但給這些破壞我們人事計畫的傢伙一個教訓，也沒有人會有意見吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......그야 물론이지.","JPN":"……もちろんだ。","ENG":"Obviously.","TWN":"……那當然。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"응당 대가를 치르게 해줄 걸세.","JPN":"きっちり代価を払わせてやる。","ENG":"They will pay the price for this.","TWN":"得讓他們付出相應的代價才行。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};